2008: func (a *Server) validateMFAAuthResponse(ctx context.Context, user string, resp *proto.MFAAuthenticateResponse, u2fStorage u2f.AuthenticationStorage) error {
2009: 	switch res := resp.Response.(type) {
2010: 	case *proto.MFAAuthenticateResponse_TOTP:
2011: 		return a.checkOTP(user, res.TOTP.Code)
2012: 	case *proto.MFAAuthenticateResponse_U2F:
2013: 		return a.checkU2F(ctx, user, u2f.AuthenticateChallengeResponse{
2014: 			KeyHandle:     res.U2F.KeyHandle,
2015: 			ClientData:    res.U2F.ClientData,
2016: 			SignatureData: res.U2F.Signature,
2017: 		}, u2fStorage)
2018: 	default:
2019: 		return trace.BadParameter("unknown or missing MFAAuthenticateResponse type %T", resp.Response)
2020: 	}
2021: }
