600: func (s *IdentityService) GetMFADevices(ctx context.Context, user string) ([]*types.MFADevice, error) {
601: 	if user == "" {
602: 		return nil, trace.BadParameter("missing parameter user")
603: 	}
604: 
605: 	startKey := backend.Key(webPrefix, usersPrefix, user, mfaDevicePrefix)
606: 	result, err := s.GetRange(ctx, startKey, backend.RangeEnd(startKey), backend.NoLimit)
607: 	if err != nil {
608: 		return nil, trace.Wrap(err)
609: 	}
610: 	devices := make([]*types.MFADevice, 0, len(result.Items))
611: 	for _, item := range result.Items {
612: 		var d types.MFADevice
613: 		if err := json.Unmarshal(item.Value, &d); err != nil {
614: 			return nil, trace.Wrap(err)
615: 		}
616: 		devices = append(devices, &d)
617: 	}
618: 	return devices, nil
619: }
