// registerU2FDevice is a helper to register a U2F device for a user
func registerU2FDevice(t *testing.T, ctx context.Context, cl *auth.Client, deviceName string, clock clockwork.FakeClock) *types.MFADevice {
	addStream, err := cl.AddMFADevice(ctx)
